<div class="flex justify-content-between align-items-center mb-3">
  <h2>רשימת תורמים</h2>

  <button
    pButton
    label="הוספת תורם"
    icon="pi pi-plus"
    class="p-button-success"
    routerLink="/donors/add">
  </button>
</div>


<p-table [value]="donors" [paginator]="true" [rows]="10">

  <ng-template pTemplate="header">
    <tr>
     <th>FirstName</th>
      <th>LastName</th>
      <th>Email</th>
      <th>Phone</th>
      <th>My Gifts</th>
    </tr>
  </ng-template>

  <ng-template pTemplate="body" let-donor>
    <tr>
      <td>{{ donor.firstName }}</td>
      <td>{{ donor.lastName }}</td>
      <td>{{ donor.email  }}</td>
      <td>{{ donor.phone }}</td>
       <a [routerLink]="['/donor-gifts', donor.id]" class="donor-link">
        myGifts
        </a>
    </tr>
  </ng-template>

</p-table>
